sql:
SELECT review_id, text, reviewer_id
FROM reviews
WHERE review_id > 0;

SELECT AVG(sentiment_id) AS average_sentiment
FROM reviews
WHERE influencer_id IN (
  SELECT user_id FROM user_roles 
  WHERE role_id = 1
);

SELECT r.name, rv.text 
FROM reviewers r
JOIN reviews rv ON r.reviewer_id = rv.reviewer_id;

SELECT review_id, text, influencer_id 
FROM reviews
WHERE review_id = (SELECT MAX(review_id) FROM reviews);

SELECT COUNT(DISTINCT r.reviewer_id) AS unique_reviewer_count
FROM reviews r
INNER JOIN adrs ad ON r.adr_id = ad.adr_id;
